// OAuth Configuration
const OAUTH_CONFIG = {
  clientId: process.env.REACT_APP_OAUTH_CLIENT_ID || 'your-client-id',
  redirectUri: process.env.REACT_APP_OAUTH_REDIRECT_URI || window.location.origin + '/callback',
  authorizationEndpoint: process.env.REACT_APP_AUTH_ENDPOINT || 'https://auth.example.com/authorize',
  tokenEndpoint: process.env.REACT_APP_TOKEN_ENDPOINT || 'https://auth.example.com/token',
  revokeEndpoint: process.env.REACT_APP_REVOKE_ENDPOINT || 'https://auth.example.com/revoke',
  userInfoEndpoint: process.env.REACT_APP_USERINFO_ENDPOINT || 'https://auth.example.com/userinfo',
  apiBaseUrl: process.env.REACT_APP_API_BASE_URL || 'https://api.example.com',
  scope: 'openid profile email',
};

// --- PKCE Utilities ---
function generateRandomString(length) {
  const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  const array = new Uint8Array(length);
  crypto.getRandomValues(array);
  return Array.from(array, (byte) => charset[byte % charset.length]).join('');
}

async function generateCodeChallenge(codeVerifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(codeVerifier);
  const digest = await crypto.subtle.digest('SHA-256', data);
  return btoa(String.fromCharCode(...new Uint8Array(digest)))
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
}

// --- Token Storage ---
const TokenStorage = {
  getAccessToken() {
    return localStorage.getItem('oauth_access_token');
  },
  getRefreshToken() {
    return localStorage.getItem('oauth_refresh_token');
  },
  getTokenExpiry() {
    const expiry = localStorage.getItem('oauth_token_expiry');
    return expiry ? parseInt(expiry, 10) : null;
  },
  getIdToken() {
    return localStorage.getItem('oauth_id_token');
  },
  setTokens({ access_token, refresh_token, expires_in, id_token }) {
    if (access_token) {
      localStorage.setItem('oauth_access_token', access_token);
    }
    if (refresh_token) {
      localStorage.setItem('oauth_refresh_token', refresh_token);
    }
    if (expires_in) {
      const expiryTime = Date.now() + expires_in * 1000;
      localStorage.setItem('oauth_token_expiry', expiryTime.toString());
    }
    if (id_token) {
      localStorage.setItem('oauth_id_token', id_token);
    }
  },
  clearTokens() {
    localStorage.removeItem('oauth_access_token');
    localStorage.removeItem('oauth_refresh_token');
    localStorage.removeItem('oauth_token_expiry');
    localStorage.removeItem('oauth_id_token');
    localStorage.removeItem('oauth_code_verifier');
    localStorage.removeItem('oauth_state');
  },
  isTokenExpired() {
    const expiry = this.getTokenExpiry();
    if (!expiry) return true;
    return Date.now() >= expiry - 60000; // 1 minute buffer
  },
  isAuthenticated() {
    return !!this.getAccessToken() && !this.isTokenExpired();
  },
};

// --- OAuth Service ---
const OAuthService = {
  async initiateLogin() {
    const state = generateRandomString(32);
    const codeVerifier = generateRandomString(64);
    const codeChallenge = await generateCodeChallenge(codeVerifier);

    localStorage.setItem('oauth_state', state);
    localStorage.setItem('oauth_code_verifier', codeVerifier);

    const params = new URLSearchParams({
      response_type: 'code',
      client_id: OAUTH_CONFIG.clientId,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      scope: OAUTH_CONFIG.scope,
      state: state,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256',
    });

    const authUrl = `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;
    window.location.href = authUrl;
  },

  async exchangeCodeForTokens(code, state) {
    const savedState = localStorage.getItem('oauth_state');
    if (state !== savedState) {
      throw new Error('State mismatch - possible CSRF attack');
    }

    const codeVerifier = localStorage.getItem('oauth_code_verifier');
    if (!codeVerifier) {
      throw new Error('Code verifier not found');
    }

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: OAUTH_CONFIG.redirectUri,
        client_id: OAUTH_CONFIG.clientId,
        code_verifier: codeVerifier,
      }).toString(),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error_description || errorData.error || 'Token exchange failed');
    }

    const tokenData = await response.json();
    TokenStorage.setTokens(tokenData);

    localStorage.removeItem('oauth_state');
    localStorage.removeItem('oauth_code_verifier');

    return tokenData;
  },

  async refreshAccessToken() {
    const refreshToken = TokenStorage.getRefreshToken();
    if (!refreshToken) {
      throw new Error('No refresh token available');
    }

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: refreshToken,
        client_id: OAUTH_CONFIG.clientId,
      }).toString(),
    });

    if (!response.ok) {
      TokenStorage.clearTokens();
      throw new Error('Token refresh failed');
    }

    const tokenData = await response.json();
    TokenStorage.setTokens(tokenData);
    return tokenData;
  },

  async revokeToken() {
    const accessToken = TokenStorage.getAccessToken();
    if (accessToken) {
      try {
        await fetch(OAUTH_CONFIG.revokeEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: new URLSearchParams({
            token: accessToken,
            client_id: OAUTH_CONFIG.clientId,
          }).toString(),
        });
      } catch (error) {
        console.warn('Token revocation failed:', error);
      }
    }
    TokenStorage.clearTokens();
  },

  async getValidAccessToken() {
    if (!TokenStorage.isTokenExpired()) {
      return TokenStorage.getAccessToken();
    }

    const refreshToken = TokenStorage.getRefreshToken();
    if (refreshToken) {
      try {
        const tokenData = await this.refreshAccessToken();
        return tokenData.access_token;
      } catch (error) {
        console.error('Token refresh failed:', error);
        throw error;
      }
    }

    throw new Error('No valid token available');
  },
};

// --- Authenticated Fetch ---
async function authenticatedFetch(url, options = {}) {
  let accessToken;
  try {
    accessToken = await OAuthService.getValidAccessToken();
  } catch (error) {
    TokenStorage.clearTokens();
    window.location.href = '/';
    throw error;
  }

  const fullUrl = url.startsWith('http') ? url : `${OAUTH_CONFIG.apiBaseUrl}${url}`;

  const response = await fetch(fullUrl, {
    ...options,
    headers: {
      ...options.headers,
      Authorization: `Bearer ${accessToken}`,
      'Content-Type': options.headers?.['Content-Type'] || 'application/json',
    },
  });

  if (response.status === 401) {
    try {
      const tokenData = await OAuthService.refreshAccessToken();
      const retryResponse = await fetch(fullUrl, {
        ...options,
        headers: {
          ...options.headers,
          Authorization: `Bearer ${tokenData.access_token}`,
          'Content-Type': options.headers?.['Content-Type'] || 'application/json',
        },
      });
      return retryResponse;
    } catch (refreshError) {
      TokenStorage.clearTokens();
      window.location.href = '/';
      throw refreshError;
    }
  }

  return response;
}

// --- Auth Context ---
const AuthContext = createContext(null);

function AuthProvider({ children }) {
  const [isAuthenticated, setIsAuthenticated] = useState(TokenStorage.isAuthenticated());
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchUserInfo = useCallback(async () => {
    try {
      const response = await authenticatedFetch(OAUTH_CONFIG.userInfoEndpoint);
      if (response.ok) {
        const userData = await response.json();
        setUser(userData);
      }
    } catch (err) {
      console.error('Failed to fetch user info:', err);
    }
  }, []);

  useEffect(() => {
    const initAuth = async () => {
      setLoading(true);
      if (TokenStorage.isAuthenticated()) {
        setIsAuthenticated(true);
        await fetchUserInfo();
      } else if (TokenStorage.getRefreshToken()) {
        try {
          await OAuthService.refreshAccessToken();
          setIsAuthenticated(true);
          await fetchUserInfo();
        } catch (err) {
          setIsAuthenticated(false);
          TokenStorage.clearTokens();
        }
      } else {
        setIsAuthenticated(false);
      }
      setLoading(false);
    };

    initAuth();
  }, [fetchUserInfo]);

  const login = useCallback(async () => {
    setError(null);
    try {
      await OAuthService.initiateLogin();
    } catch (err) {
      setError(err.message);
    }
  }, []);

  const logout = useCallback(async () => {
    setLoading(true);
    try {
      await OAuthService.revokeToken();
    } catch (err) {
      console.warn('Logout error:', err);
    }
    setUser(null);
    setIsAuthenticated(false);
    setLoading(false);
  }, []);

  const handleCallback = useCallback(
    async (code, state) => {
      setLoading(true);
      setError(null);
      try {
        await OAuthService.exchangeCodeForTokens(code, state);
        setIsAuthenticated(true);
        await fetchUserInfo();
      } catch (err) {
        setError(err.message);
        setIsAuthenticated(false);
      }
      setLoading(false);
    },
    [fetchUserInfo]
  );

  const value = {
    isAuthenticated,
    user,
    loading,
    error,
    login,
    logout,
    handleCallback,
    authenticatedFetch,
  };

  return React.createElement(AuthContext.Provider, { value }, children);
}

function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

// --- Simple Router ---
function useRouter() {
  const [path, setPath] = useState(window.location.pathname);
  const [searchParams, setSearchParams] = useState(new URLSearchParams(window.location.search));

  useEffect(() => {
    const handlePopState = () => {
      setPath(window.location.pathname);
      setSearchParams(new URLSearchParams(window.location.search));
    };
    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const navigate = useCallback((newPath) => {
    window.history.pushState({}, '', newPath);
    setPath(newPath);
    setSearchParams(new URLSearchParams(''));
  }, []);

  return { path, searchParams, navigate };
}

